/// <summary>
/// Extension of the <c>init</c> method for the ETG model.
/// </summary>
/// <remarks>This code is used to show/hide features in Spanish companies.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(InventBatchIdLookup, ETGSPAINOperationName)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventBatchIdLookup, ETGSPAINOperationStatus)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(InventBatchIdLookup, ETGSPAINPurchOperationTable_Name)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventBatchIdLookup, ETGSPAINPurchOperationTable_OperationStatus)).visible(currentCompanyIsSpanishCompany);
}
